     public async Task<string> GetPost(
         [Description("The post ID (1-100)")] int id,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching post {Id}", id);
         var post = await httpClient.GetFromJsonAsync<Post>($"posts/{id}", cancellationToken);
         return $"[{post!.Id}] {post.Title}\n\n{post.Body}";
     }

     [McpServerTool, Description("List posts, optionally filtered by author user ID.")]
     public async Task<string> ListPosts(
         [Description("Filter by author user ID (1-10). Omit to list all.")] int? userId = null,
         CancellationToken cancellationToken = default)
     {
         var url = userId.HasValue ? $"posts?userId={userId}" : "posts";
         logger.LogInformation("Listing posts from {Url}", url);

         var posts = await httpClient.GetFromJsonAsync<List<Post>>(url, cancellationToken);
         return string.Join("\n", posts!.Select(p => $"[{p.Id}] {p.Title}"));
     }

     [McpServerTool(ReadOnly = false), Description("Create a new blog post.")]
     public async Task<string> CreatePost(
         [Description("Author user ID")] int userId,
         [Description("Post title")] string title,
         [Description("Post body text")] string body,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Creating post for user {UserId}", userId);
         var response = await httpClient.PostAsJsonAsync("posts",
             new { userId, title, body }, cancellationToken);
         response.EnsureSuccessStatusCode();

         var created = await response.Content.ReadFromJsonAsync<Post>(cancellationToken);
         return $"Created post with ID {created!.Id}: {created.Title}";
     }

     [McpServerTool, Description("Search posts whose title or body contains the query text.")]
     public async Task<string> SearchPosts(
         [Description("Text to search for in titles and bodies")] string query,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Searching posts for '{Query}'", query);
         var posts = await httpClient.GetFromJsonAsync<List<Post>>("posts", cancellationToken);

         var matches = posts!
             .Where(p => p.Title.Contains(query, StringComparison.OrdinalIgnoreCase)
                      || p.Body.Contains(query, StringComparison.OrdinalIgnoreCase))
             .ToList();

         return matches.Count == 0
             ? "No posts matched your query."
             : string.Join("\n", matches.Select(p => $"[{p.Id}] {p.Title}"));
     }
 }

 public record Post(
     [property: JsonPropertyName("userId")] int UserId,
     [property: JsonPropertyName("id")] int Id,
     [property: JsonPropertyName("title")] string Title,
     [property: JsonPropertyName("body")] string Body);
